#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, i;
    int *arr;

    printf("Enter number of elements: ");
    scanf("%d", &n);

    // Allocate memory for n integers
    arr = (int*)malloc(n * sizeof(int));

    // Check if allocation succeeded
    if (arr == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Accept elements from user
    printf("Enter %d integers: ", n);
    for (i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    // Display elements
    printf("Elements: ");
    for (i = 0; i < n; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    // Free allocated memory
    free(arr);
    arr = NULL;  // Prevent dangling pointer

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int rows = 3, cols = 4;
    int **matrix;
    int i, j;

    // Step 1: Allocate array of row pointers
    matrix = (int**)malloc(rows * sizeof(int*));
    if (matrix == NULL) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Step 2: Allocate memory for each row
    for (i = 0; i < rows; i++) {
        matrix[i] = (int*)malloc(cols * sizeof(int));
        if (matrix[i] == NULL) {
            printf("Memory allocation failed\n");
            // Free previously allocated rows
            for (j = 0; j < i; j++) {
                free(matrix[j]);
            }
            free(matrix);
            return 1;
        }
    }

    // Initialize matrix elements
    int count = 1;
    for (i = 0; i < rows; i++) {
        for (j = 0; j < cols; j++) {
            matrix[i][j] = count++;
        }
    }

    // Display matrix
    printf("3x4 Matrix:\n");
    for (i = 0; i < rows; i++) {
        for (j = 0; j < cols; j++) {
            printf("%4d", matrix[i][j]);
        }
        printf("\n");
    }

    // Free memory - MUST free in reverse order
    for (i = 0; i < rows; i++) {
        free(matrix[i]);  // Free each row
    }
    free(matrix);  // Free array of pointers
    matrix = NULL;

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int *arr = NULL;    // Start with NULL (first realloc acts like malloc)
    int size = 0;       // Current number of elements
    int capacity = 0;  // Current allocated capacity
    int value;

    printf("Enter integers (0 to stop):\n");

    while (scanf("%d", &value) == 1 && value != 0) {
        // Check if we need more space
        if (size >= capacity) {
            int newCapacity = (capacity == 0) ? 4 : capacity * 2;
            int *temp = (int*)realloc(arr, newCapacity * sizeof(int));

            if (temp == NULL) {
                printf("Memory allocation failed!\n");
                free(arr);  // Free existing memory before exit
                return 1;
            }

            arr = temp;
            capacity = newCapacity;
            printf("Array capacity grown to %d\n", capacity);
        }

        arr[size] = value;
        size++;
    }

    // Display final array
    printf("\nYou entered %d elements:\n", size);
    for (int i = 0; i < size; i++) {
        printf("arr[%d] = %d\n", i, arr[i]);
    }

    // Free memory
    free(arr);
    arr = NULL;

    return 0;
}
